"use client";

/**
 * Banner Section Component
 *
 * A promotional banner section with multiple style variants.
 */

import React from "react";
import { X } from "lucide-react";
import { Button } from "../../components/Button";
import type { BannerProps } from "./Banner.types";
import styles from "./Banner.module.css";

/**
 * Banner section for promotions and announcements
 */
export const Banner: React.FC<BannerProps> = ({
  eyebrow,
  title,
  description,
  ctaLabel,
  ctaHref,
  secondaryCtaLabel,
  secondaryCtaHref,
  variant = "default",
  backgroundImage,
  sideImage,
  imagePosition = "right",
  backgroundColor,
  gradient,
  dismissible = false,
  onDismiss,
  fullWidth = false,
  compact = false,
  centered = true,
  className,
  style,
  ...rest
}) => {
  const customStyle: React.CSSProperties = {
    ...style,
    ...(backgroundImage &&
      variant === "image" && {
        backgroundImage: `url(${backgroundImage})`,
      }),
    ...(backgroundColor && { backgroundColor }),
    ...(gradient &&
      variant === "gradient" && {
        background: gradient,
      }),
  };

  const renderContent = () => (
    <div className={styles.content}>
      {eyebrow && <span className={styles.eyebrow}>{eyebrow}</span>}
      <h2 className={styles.title}>{title}</h2>
      {description && <p className={styles.description}>{description}</p>}
      {(ctaLabel || secondaryCtaLabel) && (
        <div className={styles.actions}>
          {ctaLabel && ctaHref && (
            <Button
              variant={variant === "split" ? "primary" : "inverse"}
              onClick={() => (window.location.href = ctaHref)}
            >
              {ctaLabel}
            </Button>
          )}
          {secondaryCtaLabel && secondaryCtaHref && (
            <Button
              variant={variant === "split" ? "secondary" : "ghost"}
              onClick={() => (window.location.href = secondaryCtaHref)}
            >
              {secondaryCtaLabel}
            </Button>
          )}
        </div>
      )}
    </div>
  );

  return (
    <section
      className={`${styles.banner} ${className || ""}`}
      data-variant={variant}
      data-compact={compact}
      data-centered={centered && variant !== "split"}
      data-full-width={fullWidth}
      style={customStyle}
      {...rest}
    >
      <div className={styles.container}>
        {variant === "split" && sideImage ? (
          <div
            className={styles.splitLayout}
            data-image-position={imagePosition}
          >
            <div className={styles.splitContent}>{renderContent()}</div>
            <img
              src={sideImage}
              alt=""
              className={styles.splitImage}
              aria-hidden="true"
            />
          </div>
        ) : (
          renderContent()
        )}
      </div>

      {dismissible && (
        <div className={styles.dismissButton}>
          <Button
            iconOnly
            icon={<X size={20} />}
            variant="ghost"
            onClick={onDismiss}
            aria-label="Dismiss banner"
          />
        </div>
      )}
    </section>
  );
};

Banner.displayName = "Banner";

/**
 * Banner Section Types
 *
 * Type definitions for the Orion Banner section component.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Banner variant styles
 */
export type BannerVariant = "default" | "gradient" | "image" | "split";

/**
 * Banner section props
 *
 * @example
 * ```tsx
 * <Banner
 *   title="Summer Sale"
 *   description="Up to 50% off on selected items"
 *   ctaLabel="Shop Now"
 *   ctaHref="/sale"
 *   variant="gradient"
 * />
 * ```
 */
export interface BannerProps extends Omit<
  HTMLAttributes<HTMLElement>,
  "title"
> {
  /**
   * Optional eyebrow/badge text
   */
  eyebrow?: ReactNode;

  /**
   * Banner title
   */
  title: ReactNode;

  /**
   * Banner description
   */
  description?: ReactNode;

  /**
   * Primary CTA button label
   */
  ctaLabel?: string;

  /**
   * Primary CTA button href
   */
  ctaHref?: string;

  /**
   * Secondary CTA label
   */
  secondaryCtaLabel?: string;

  /**
   * Secondary CTA href
   */
  secondaryCtaHref?: string;

  /**
   * Banner variant
   * @default 'default'
   */
  variant?: BannerVariant;

  /**
   * Background image URL (for 'image' and 'split' variants)
   */
  backgroundImage?: string;

  /**
   * Side image URL (for 'split' variant)
   */
  sideImage?: string;

  /**
   * Image position for split variant
   * @default 'right'
   */
  imagePosition?: "left" | "right";

  /**
   * Custom background color
   */
  backgroundColor?: string;

  /**
   * Custom gradient (overrides default)
   */
  gradient?: string;

  /**
   * Dismissible banner
   * @default false
   */
  dismissible?: boolean;

  /**
   * On dismiss callback
   */
  onDismiss?: () => void;

  /**
   * Full width (no max-width constraint)
   * @default false
   */
  fullWidth?: boolean;

  /**
   * Compact mode
   * @default false
   */
  compact?: boolean;

  /**
   * Center content
   * @default true
   */
  centered?: boolean;
}

/**
 * Banner Section Styles
 */

.banner {
  position: relative;
  padding: var(--spacing-16) var(--spacing-4);
  overflow: hidden;
}

.banner[data-compact="true"] {
  padding: var(--spacing-8) var(--spacing-4);
}

/* Variants */
.banner[data-variant="default"] {
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
}

.banner[data-variant="gradient"] {
  background: linear-gradient(
    135deg,
    var(--interactive-primary),
    var(--interactive-primary-hover)
  );
  color: var(--interactive-primary-text);
}

.banner[data-variant="image"] {
  background-size: cover;
  background-position: center;
  color: var(--text-on-dark);
}

.banner[data-variant="image"]::before {
  content: "";
  position: absolute;
  inset: 0;
  background: var(--overlay-dark);
}

.banner[data-variant="split"] {
  background: var(--surface-subtle);
  color: var(--text-primary);
}

/* Container */
.container {
  position: relative;
  max-width: var(--container-width, 1200px);
  margin: 0 auto;
  z-index: var(--z-dropdown);
}

.banner[data-full-width="true"] .container {
  max-width: none;
}

/* Content */
.content {
  max-width: var(--size-modal-lg);
}

.banner[data-centered="true"] .content {
  margin: 0 auto;
  text-align: center;
}

/* Split Layout */
.splitLayout {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: var(--spacing-12);
  align-items: center;
}

.splitLayout[data-image-position="left"] {
  direction: rtl;
}

.splitLayout[data-image-position="left"] > * {
  direction: ltr;
}

.splitContent {
  max-width: none;
}

.splitImage {
  width: 100%;
  height: auto;
  border-radius: var(--radius-container);
  object-fit: cover;
}

/* Eyebrow */
.eyebrow {
  display: inline-block;
  font-size: var(--font-size-12);
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: var(--letter-spacing-wide);
  margin-bottom: var(--spacing-3);
  padding: var(--spacing-1) var(--spacing-3);
  background: color-mix(in srgb, var(--color-neutral-0) 20%, transparent);
  border-radius: var(--radius-full);
}

.banner[data-variant="split"] .eyebrow {
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
}

/* Title */
.title {
  font-family: var(--font-primary);
  font-size: var(--font-size-48);
  font-weight: 600;
  margin: 0 0 var(--spacing-4) 0;
  line-height: var(--line-height-tight);
  color: inherit;
}

.banner[data-compact="true"] .title {
  font-size: var(--font-size-32);
}

/* Description */
.description {
  font-size: var(--font-size-20);
  color: currentColor;
  margin: 0 0 var(--spacing-8) 0;
  line-height: var(--line-height-relaxed);
}

.banner[data-compact="true"] .description {
  font-size: var(--font-size-16);
  margin-bottom: var(--spacing-6);
}

/* Actions */
.actions {
  display: flex;
  gap: var(--spacing-4);
  flex-wrap: wrap;
}

.banner[data-centered="true"] .actions {
  justify-content: center;
}

/* Dismiss Button */
.dismissButton {
  position: absolute;
  top: var(--spacing-4);
  right: var(--spacing-4);
  z-index: var(--z-modal);
}

.dismissButton button {
  background: color-mix(in srgb, var(--color-neutral-0) 20%, transparent);
  color: inherit;
}

.dismissButton button:hover {
  background: color-mix(in srgb, var(--color-neutral-0) 30%, transparent);
}

.banner[data-variant="split"] .dismissButton button {
  background: var(--surface-subtle);
}

.banner[data-variant="split"] .dismissButton button:hover {
  background: var(--surface-layer);
}

/* Responsive */
@media (max-width: 768px) {
  .banner {
    padding: var(--spacing-12) var(--spacing-4);
  }

  .title {
    font-size: var(--font-size-32);
  }

  .splitLayout {
    grid-template-columns: 1fr;
    gap: var(--spacing-8);
  }

  .splitLayout[data-image-position="left"] {
    direction: ltr;
  }

  .actions {
    width: 100%;
  }
}
